import{_ as e,o as t,c as a,Q as i}from"./chunks/framework.b67c47e6.js";const f=JSON.parse('{"title":"Setting Up IFC Parsing","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/ifcps/index.md","filePath":"tutorials/ifcps/index.md","lastUpdated":1773939149000}'),r={name:"tutorials/ifcps/index.md"},o=i('<h1 id="setting-up-ifc-parsing" tabindex="-1">Setting Up IFC Parsing <a class="header-anchor" href="#setting-up-ifc-parsing" aria-label="Permalink to &quot;Setting Up IFC Parsing&quot;">​</a></h1><p>This tutorial walks you through configuring an IFC Parsing Setup (IFC PS) so that produuz.it can correctly interpret your IFC files and extract parts, materials, and properties.</p><nav class="table-of-contents"><ul><li><a href="#prerequisites">Prerequisites</a></li><li><a href="#what-is-an-ifc-parsing-setup">What is an IFC Parsing Setup?</a></li><li><a href="#step-1-create-an-ifc-parsing-setup">Step 1: Create an IFC Parsing Setup</a></li><li><a href="#step-2-configure-part-detection">Step 2: Configure Part Detection</a><ul><li><a href="#category-mapping">Category Mapping</a></li><li><a href="#branch-detection">Branch Detection</a></li></ul></li><li><a href="#step-3-configure-material-detection">Step 3: Configure Material Detection</a></li><li><a href="#step-4-configure-dimensions">Step 4: Configure Dimensions</a></li><li><a href="#step-5-configure-hidden-materials-optional">Step 5: Configure Hidden Materials (Optional)</a></li><li><a href="#step-6-test-your-configuration">Step 6: Test Your Configuration</a></li><li><a href="#step-7-assign-to-projects">Step 7: Assign to Projects</a></li><li><a href="#next-steps">Next Steps</a></li></ul></nav><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>You must have <strong>manager</strong> or <strong>admin</strong> access.</li><li>Have a sample IFC file ready to test your configuration.</li></ul><h2 id="what-is-an-ifc-parsing-setup" tabindex="-1">What is an IFC Parsing Setup? <a class="header-anchor" href="#what-is-an-ifc-parsing-setup" aria-label="Permalink to &quot;What is an IFC Parsing Setup?&quot;">​</a></h2><p>An IFC Parsing Setup defines the rules for how produuz.it reads your IFC files. Different companies and BIM software produce IFC files with different structures and property naming conventions. The IFC PS tells the system where to find the information it needs.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>For a detailed reference of all IFC PS fields, see the <a href="/guide/management/ifcps/">IFC Parsing Setup guide</a>.</p></div><h2 id="step-1-create-an-ifc-parsing-setup" tabindex="-1">Step 1: Create an IFC Parsing Setup <a class="header-anchor" href="#step-1-create-an-ifc-parsing-setup" aria-label="Permalink to &quot;Step 1: Create an IFC Parsing Setup&quot;">​</a></h2><ol><li>Go to <strong>Company Settings &gt; IFC Parsing Setup</strong> (or access it from a project&#39;s settings).</li><li>Click <strong>Add IFC PS</strong>.</li><li>Give it a descriptive name (e.g., &quot;Cadwork Standard&quot; or &quot;Tekla Wall Panels&quot;).</li></ol><h2 id="step-2-configure-part-detection" tabindex="-1">Step 2: Configure Part Detection <a class="header-anchor" href="#step-2-configure-part-detection" aria-label="Permalink to &quot;Step 2: Configure Part Detection&quot;">​</a></h2><p>The most important configuration is telling the system how to identify and categorize parts from your IFC file.</p><h3 id="category-mapping" tabindex="-1">Category Mapping <a class="header-anchor" href="#category-mapping" aria-label="Permalink to &quot;Category Mapping&quot;">​</a></h3><p>Define how IFC objects are mapped to produuz.it categories:</p><ul><li><strong>Wood</strong> — Structural timber members (studs, plates, beams).</li><li><strong>Plates</strong> — Sheet materials (OSB, plasterboard, cladding).</li><li><strong>Accessories</strong> — Hardware, fasteners, insulation, etc.</li></ul><p>For each category, specify which <strong>IFC property</strong> and <strong>value</strong> identifies parts of that type. For example:</p><ul><li>Property: <code>ObjectType</code>, Value contains: <code>Stud</code> → <strong>Wood</strong></li><li>Property: <code>ObjectType</code>, Value contains: <code>Plate</code> → <strong>Plates</strong></li></ul><h3 id="branch-detection" tabindex="-1">Branch Detection <a class="header-anchor" href="#branch-detection" aria-label="Permalink to &quot;Branch Detection&quot;">​</a></h3><p>Branches further classify parts within a category (e.g., different wood types, interior vs. exterior plates). Configure rules to detect branches based on IFC properties.</p><h2 id="step-3-configure-material-detection" tabindex="-1">Step 3: Configure Material Detection <a class="header-anchor" href="#step-3-configure-material-detection" aria-label="Permalink to &quot;Step 3: Configure Material Detection&quot;">​</a></h2><p>Set up how the system reads material information:</p><ul><li><strong>Material property</strong> — Which IFC property holds the material name.</li><li><strong>Material mapping</strong> — Map IFC material names to your <a href="/guide/stock/">Stock &amp; Products</a> catalog.</li></ul><h2 id="step-4-configure-dimensions" tabindex="-1">Step 4: Configure Dimensions <a class="header-anchor" href="#step-4-configure-dimensions" aria-label="Permalink to &quot;Step 4: Configure Dimensions&quot;">​</a></h2><p>Specify which IFC properties contain dimensional data:</p><ul><li><strong>Width, Height, Length, Thickness</strong> — Map to the corresponding IFC properties.</li><li><strong>Reference number</strong> — How to extract part reference codes.</li></ul><h2 id="step-5-configure-hidden-materials-optional" tabindex="-1">Step 5: Configure Hidden Materials (Optional) <a class="header-anchor" href="#step-5-configure-hidden-materials-optional" aria-label="Permalink to &quot;Step 5: Configure Hidden Materials (Optional)&quot;">​</a></h2><p>Some parts should be present in the BOM but hidden in the 3D viewer (e.g., insulation, membranes):</p><ul><li>Mark specific categories or branches as &quot;hidden materials&quot;.</li><li>These parts won&#39;t display in the 3D view by default (can be toggled in company settings).</li></ul><h2 id="step-6-test-your-configuration" tabindex="-1">Step 6: Test Your Configuration <a class="header-anchor" href="#step-6-test-your-configuration" aria-label="Permalink to &quot;Step 6: Test Your Configuration&quot;">​</a></h2><ol><li>Go to a project and upload a sample IFC file.</li><li>Run <strong>Generate Designs</strong> on the uploaded file.</li><li>Open the generated design in the Viewer.</li><li>Verify: <ul><li>Parts are correctly categorized (check the BOM panel).</li><li>Materials are correctly detected.</li><li>Dimensions are accurate.</li><li>Hidden parts behave as expected.</li></ul></li></ol><p>If parts appear as &quot;unknown&quot; in the BOM, your parsing rules likely need adjustment for those object types.</p><h2 id="step-7-assign-to-projects" tabindex="-1">Step 7: Assign to Projects <a class="header-anchor" href="#step-7-assign-to-projects" aria-label="Permalink to &quot;Step 7: Assign to Projects&quot;">​</a></h2><p>Once your IFC PS is working correctly:</p><ol><li>Go to any project&#39;s settings.</li><li>Select your IFC PS as the parsing strategy for that project.</li><li>All future file uploads in that project will use this configuration.</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You can create multiple IFC Parsing Setups for different BIM software or project types. Assign the appropriate one per project.</p></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/tutorials/projects/">Build a Project</a> — Upload files and generate designs using your IFC PS.</li><li><a href="/tutorials/production_lines/">Production Lines Setup</a> — Configure your production workflow.</li></ul>',37),n=[o];function s(l,p,c,u,d,h){return t(),a("div",null,n)}const m=e(r,[["render",s]]);export{f as __pageData,m as default};
